import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, PermissionsAndroid, Platform } from 'react-native';
import * as Location from 'expo-location';

const App: React.FC = () => {
  const [latitude, setLatitude] = useState(null);
  const [longitude, setLongitude] = useState(null);

  useEffect(() => {
    const fetchLocation = async () => {
      try {
        let { status } = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,
          {
            title: 'Location Permission',
            message: 'This app needs your location to work',
            buttonNeutral: 'Ask Me',
            buttonNegative: 'Close',
            buttonPositive: 'OK'
          }
        );

        if (status !== PermissionsAndroid.PERMISSIONS_GRANTED) {
          await Promise.all([
            Location.requestForegroundPermissionsAsync(),
            fetchLocation()
          ]);
        } else {
          setLatitude(await Location.getCurrentPosition({ accuracy: Location.AUTHORITATIVE }));
          setLongitude(await Location.getCurrentPosition());
        }
      } catch (error) {
        console.error('Error fetching location:', error);
      }
    };

    fetchLocation();
  }, []);

  return (
    <View style={styles.container}>
      {latitude !== null && longitude !== null ? (
        <Text style={styles.info}>
          Latitude: {latitude.toFixed(4)} | Longitude: {longitude.toFixed(4)}
        </Text>
      ) : (
        <Text style={styles.info}>Loading location...</Text>
      )}
    </View>
  );
};

