import React, { useState, useEffect } from 'react';
import { View, Text, FlatList, TextInput, Button, StyleSheet } from 'react-native';
import SQLite from 'expo-sqlite';

const App = () => {
  const [todos, setTodos] = useState<any[]>([]);
  const db = new SQLite.Database();
  const dbVersion = db.version();

  useEffect(() => {
    if (!db.exists()) {
      db.execute(
        'CREATE TABLE todos (id INTEGER PRIMARY KEY AUTOINCREMENT, text TEXT)'
      );
    }
    loadTodos();
  }, []);

  const loadTodos = () => {
    db.query('SELECT * FROM todos', (error, results) => {
      if (error) return;
      setTodos(results.map(row => ({ id: row.id, text: row.text })));
    });
  };

  const addTodo = (text: string) => {
    db.transaction(txn => {
      txn.execute('INSERT INTO todos (text) VALUES (?)', [text]);
      setTodos([...todos, { id: Date.now(), text }]);
    });
  };

  const deleteTodo = (id: number) => {
    db.transaction(txn => {
      txn.execute('DELETE FROM todos WHERE id = ?', [id]);
      setTodos(todos.filter(todo => todo.id !== id));
    });
  };

  const renderItem = ({ item }: { item: any }) => (
    <Text style={styles.todoText}>{item.text}</Text>
  );

  return (
    <View style={styles.container}>
      <TextInput
        placeholder="Add a new todo"
        value={todos.length ? '' : ''}
        onChangeText={text => addTodo(text)}
        style={styles.input}
      />
      <Button title="Add" onPress={() => addTodo('New Todo')} />
      <FlatList
        data={todos}
        renderItem={renderItem}
        keyExtractor={item => item.id.toString()}
      />
      <Button title="Delete" onPress={(id) => deleteTodo(id)} />
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 20 },
  input: { borderWidth: 1, marginBottom: 10, padding: 8 },
  todoText: { fontSize: 18 }
});

export default App;

