  const panGesture = useRef<PanGestureHandler>(null)(null);
  const snapGesture = useRef<ReactNativeGestureHandler>(null)(null);

  const pan = panGesture.current;

  const snapToOriginal = (position: { x: number, y: number }) => {
    const originalX = position.position.x;
    const originalY = position.position.y;
    const distance = Math.sqrt((originalX - position.x) ** 2 + (originalY - position.y) ** 2);
    if (distance < 10) { // snap within 10 units
      position.position = {
        x: originalX,
        y: originalY,
      };
    }
  };

  useEffect(() => {
    panGesture.current.onStart={() => snapToOriginal(position)}};
    panGesture.current.onMove={(event) => {
      const newPos = { x: event.location.x, y: event.location.y };
      position.position = newPos;
      snapToOriginal(newPos);
    });
    panGesture.current.onEnd={onPanEnd};

    return () => {
      panGesture.current.removeEventListener('start', null);
      panGesture.current.removeEventListener('move', null);
      panGesture.current.removeEventListener('end', onPanEnd);
    };
  }, [position]);

  const onPanEnd = () => {
    // Snap back to original position
    const snapPos = { x: position.position.x, y: position.position.y };
    setPosition(snapPos);
  };

  return (
    <View style={styles.box}>
      <Animated.View
        style={styles.boxContent}
        transform={[
          { translateX: panGesture.current?.translationX },
          { translateY: panGesture.current?.translationY },
        ]}
      >
        <Text style={styles.text}>Snap Back</Text>
      </Animated.View>
    </View>
  );
};

const styles = StyleSheet.create({
  box: {
    width: SCREEN_WIDTH,
    height: 100,
    backgroundColor: '#fff',
    margin: 10,
  },
  boxContent: {
    padding: 20,
    alignItems: 'center',
  },
  text: {
    fontSize: 16,
    textAlign: 'center',
  },
});

export default function App() {
  const position = useRef({ x: 0, y: 0 }).current;

  return (
    <PanGestureHandler onStart={() => position.current = { ...position.current, x: 0, y: 0 }}>
      <Box position={position.current} onPanEnd={onPanEnd} />
    </PanGestureHandler>
  );
}

